// Generated by claude-internal tools.

const P = window.__PREFIX__ || '';
let pieChart = null, barChart = null, trendChart = null;
let currentPage = 1;

const COLORS = [
    '#4a90d9', '#e74c3c', '#27ae60', '#f39c12', '#9b59b6',
    '#1abc9c', '#e67e22', '#2c3e50', '#d35400', '#16a085',
    '#c0392b', '#8e44ad', '#2980b9', '#f1c40f'
];

document.addEventListener('DOMContentLoaded', () => {
    // Set default dates: this year
    const now = new Date();
    document.getElementById('dateFrom').value = `${now.getFullYear()}-01-01`;
    document.getElementById('dateTo').value = now.toISOString().split('T')[0];

    // Load card options
    loadCardOptions();

    document.getElementById('applyFilter').addEventListener('click', applyFilters);
    document.getElementById('searchBtn').addEventListener('click', () => { currentPage = 1; loadTransactions(); });
    document.getElementById('searchInput').addEventListener('keydown', (e) => {
        if (e.key === 'Enter') { currentPage = 1; loadTransactions(); }
    });

    applyFilters();
});

async function loadCardOptions() {
    try {
        const res = await fetch(P + '/api/dashboard');
        const data = await res.json();
        const sel = document.getElementById('cardFilter');
        for (const card of data.cards) {
            const opt = document.createElement('option');
            opt.value = card;
            opt.textContent = `尾号 ${card}`;
            sel.appendChild(opt);
        }
    } catch (e) { /* ignore */ }
}

function getFilters() {
    return {
        date_from: document.getElementById('dateFrom').value,
        date_to: document.getElementById('dateTo').value,
        card: document.getElementById('cardFilter').value,
    };
}

async function applyFilters() {
    const f = getFilters();
    await Promise.all([
        loadCategoryData(f),
        loadMonthlyTrend(f),
        loadTop20(f),
    ]);
    currentPage = 1;
    loadTransactions();
}

async function loadCategoryData(filters) {
    try {
        const params = new URLSearchParams(filters);
        const res = await fetch(`${P}/api/analysis/category?${params}`);
        const json = await res.json();
        renderPieChart(json.data);
        renderBarChart(json.data);
        updateCategoryFilter(json.data);
        updateTotalAmount(json.data);
    } catch (e) {
        console.error('Category load error:', e);
    }
}

function renderPieChart(data) {
    const ctx = document.getElementById('categoryPieChart').getContext('2d');
    if (pieChart) pieChart.destroy();

    const grandTotal = data.reduce((s, d) => s + d.total, 0);

    pieChart = new Chart(ctx, {
        type: 'doughnut',
        data: {
            labels: data.map(d => d.category),
            datasets: [{
                data: data.map(d => d.total),
                backgroundColor: COLORS.slice(0, data.length),
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: {
                    position: 'right',
                    labels: {
                        font: { size: 12 },
                        generateLabels: (chart) => {
                            const ds = chart.data.datasets[0];
                            return chart.data.labels.map((label, i) => {
                                const val = ds.data[i];
                                const pct = grandTotal > 0 ? (val / grandTotal * 100).toFixed(2) : '0.00';
                                return {
                                    text: `${label}  ${pct}%`,
                                    fillStyle: ds.backgroundColor[i],
                                    strokeStyle: ds.backgroundColor[i],
                                    lineWidth: 0,
                                    hidden: false,
                                    index: i,
                                };
                            });
                        }
                    }
                },
                tooltip: {
                    callbacks: {
                        label: (ctx) => {
                            const pct = grandTotal > 0 ? (ctx.parsed / grandTotal * 100).toFixed(2) : '0.00';
                            return `${ctx.label}: ¥${ctx.parsed.toLocaleString('zh-CN', {minimumFractionDigits: 2})} (${pct}%)`;
                        }
                    }
                }
            }
        }
    });
}

function renderBarChart(data) {
    const ctx = document.getElementById('categoryBarChart').getContext('2d');
    if (barChart) barChart.destroy();

    const top10 = data.slice(0, 10);
    const grandTotal = data.reduce((s, d) => s + d.total, 0);

    barChart = new Chart(ctx, {
        type: 'bar',
        data: {
            labels: top10.map(d => d.category),
            datasets: [{
                label: '消费金额',
                data: top10.map(d => d.total),
                backgroundColor: COLORS.slice(0, top10.length),
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            indexAxis: 'y',
            plugins: {
                legend: { display: false },
                tooltip: {
                    callbacks: {
                        label: (ctx) => {
                            const pct = grandTotal > 0 ? (ctx.parsed.x / grandTotal * 100).toFixed(2) : '0.00';
                            return `¥${ctx.parsed.x.toLocaleString('zh-CN', {minimumFractionDigits: 2})} (${pct}%)`;
                        }
                    }
                },
                datalabels: false
            },
            scales: {
                x: { ticks: { callback: v => '¥' + v.toLocaleString() } }
            }
        },
        plugins: [{
            id: 'barPercentLabels',
            afterDatasetsDraw(chart) {
                const { ctx: c, data: chartData } = chart;
                c.save();
                c.font = '11px sans-serif';
                c.fillStyle = '#555';
                c.textAlign = 'left';
                c.textBaseline = 'middle';
                const meta = chart.getDatasetMeta(0);
                meta.data.forEach((bar, i) => {
                    const val = chartData.datasets[0].data[i];
                    const pct = grandTotal > 0 ? (val / grandTotal * 100).toFixed(2) : '0.00';
                    const label = `¥${val.toLocaleString('zh-CN', {minimumFractionDigits: 2})} (${pct}%)`;
                    c.fillText(label, bar.x + 6, bar.y);
                });
                c.restore();
            }
        }]
    });
}

async function loadMonthlyTrend(filters) {
    try {
        const params = new URLSearchParams({ date_from: filters.date_from, date_to: filters.date_to });
        const res = await fetch(`${P}/api/analysis/monthly-trend?${params}`);
        const json = await res.json();
        renderTrendChart(json);
    } catch (e) {
        console.error('Trend load error:', e);
    }
}

function renderTrendChart(data) {
    const ctx = document.getElementById('monthlyTrendChart').getContext('2d');
    if (trendChart) trendChart.destroy();

    const datasets = [];
    let i = 0;
    for (const [card, monthData] of Object.entries(data.trend)) {
        datasets.push({
            label: `卡 ${card}`,
            data: data.months.map(m => (monthData[m] || {}).total || 0),
            borderColor: COLORS[i],
            backgroundColor: COLORS[i] + '20',
            fill: true,
            tension: 0.3,
        });
        i++;
    }

    // Add total line
    if (Object.keys(data.trend).length > 1) {
        datasets.push({
            label: '合计',
            data: data.months.map(m => {
                let sum = 0;
                for (const card of Object.values(data.trend)) {
                    sum += (card[m] || {}).total || 0;
                }
                return sum;
            }),
            borderColor: '#333',
            borderDash: [5, 5],
            fill: false,
            tension: 0.3,
        });
    }

    trendChart = new Chart(ctx, {
        type: 'line',
        data: { labels: data.months, datasets },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            interaction: { mode: 'index', intersect: false },
            plugins: { legend: { position: 'top' } },
            scales: {
                y: { ticks: { callback: v => '¥' + v.toLocaleString() } }
            }
        }
    });
}

function updateCategoryFilter(data) {
    const sel = document.getElementById('categoryFilter');
    const current = sel.value;
    sel.innerHTML = '<option value="">全部分类</option>';
    for (const d of data) {
        const opt = document.createElement('option');
        opt.value = d.category;
        opt.textContent = `${d.category} (${d.count})`;
        sel.appendChild(opt);
    }
    sel.value = current;
}

function updateTotalAmount(data) {
    const total = data.reduce((s, d) => s + d.total, 0);
    const count = data.reduce((s, d) => s + d.count, 0);
    const el = document.getElementById('totalAmount');
    document.getElementById('totalAmountValue').textContent = `¥${total.toLocaleString('zh-CN', {minimumFractionDigits: 2})}`;
    document.getElementById('totalAmountCount').textContent = `${count} 笔`;
    el.style.display = 'flex';
}

async function loadTop20(filters) {
    try {
        const params = new URLSearchParams({
            ...filters,
            sort: 'amount',
            page: 1,
            per_page: 20,
        });
        const res = await fetch(`${P}/api/analysis/transactions?${params}`);
        const json = await res.json();
        renderTop20(json.data || []);
    } catch (e) {
        console.error('Top20 load error:', e);
    }
}

function renderTop20(items) {
    const card = document.getElementById('top20Card');
    const leftList = document.getElementById('top20Left');
    const rightList = document.getElementById('top20Right');
    if (!items.length) {
        card.style.display = 'none';
        return;
    }
    const maxAmount = items[0].amount;
    const barColors = [
        '#e74c3c', '#e67e22', '#f39c12', '#27ae60', '#4a90d9',
        '#9b59b6', '#1abc9c', '#2c3e50', '#d35400', '#16a085',
        '#c0392b', '#8e44ad', '#2980b9', '#f1c40f'
    ];
    const renderItem = (t, i) => {
        const pct = maxAmount > 0 ? (t.amount / maxAmount * 100).toFixed(1) : 0;
        const color = barColors[i % barColors.length];
        return `
        <div class="top10-item">
            <div class="top10-rank">${i + 1}</div>
            <div class="top10-info">
                <div class="top10-header">
                    <span class="top10-merchant" title="${t.merchant}">${t.merchant}</span>
                    <span class="top10-amount">¥${Number(t.amount).toLocaleString('zh-CN', {minimumFractionDigits: 2})}</span>
                </div>
                <div class="top10-bar-bg">
                    <div class="top10-bar" style="width:${pct}%;background:${color};"></div>
                </div>
                <div class="top10-meta">
                    <span class="top10-date">${t.trans_date}</span>
                    <span class="badge badge-info" style="font-size:10px;">${t.category}</span>
                    <span class="top10-date">尾号${t.card_last4}</span>
                </div>
            </div>
        </div>`;
    };
    const half = Math.ceil(items.length / 2);
    leftList.innerHTML = items.slice(0, half).map((t, i) => renderItem(t, i)).join('');
    rightList.innerHTML = items.slice(half).map((t, i) => renderItem(t, i + half)).join('');
    card.style.display = '';
}

async function loadTransactions() {
    const f = getFilters();
    const params = new URLSearchParams({
        ...f,
        category: document.getElementById('categoryFilter').value,
        search: document.getElementById('searchInput').value,
        page: currentPage,
        per_page: 20,
    });

    try {
        const res = await fetch(`${P}/api/analysis/transactions?${params}`);
        const json = await res.json();
        renderTransactions(json);
    } catch (e) {
        console.error('Transaction load error:', e);
    }
}

function renderTransactions(json) {
    const tbody = document.getElementById('transBody');
    if (!json.data || json.data.length === 0) {
        tbody.innerHTML = '<tr><td colspan="7" class="loading-text">无数据</td></tr>';
        document.getElementById('pagination').innerHTML = '';
        return;
    }

    tbody.innerHTML = json.data.map(t => {
        const refundedClass = t.refunded ? ' style="opacity:0.45;text-decoration:line-through;"' : '';
        const refundBadge = t.refunded ? `<span class="badge badge-danger" title="退货日期: ${t.refund_date || ''}">已退货</span>` : '';
        return `
        <tr${refundedClass}>
            <td>${t.trans_date}</td>
            <td>${t.post_date || '-'}</td>
            <td>${t.card_last4}</td>
            <td>${t.merchant} ${refundBadge}</td>
            <td><span class="badge badge-info">${t.category}</span></td>
            <td style="font-weight:600;color:${t.refunded ? '#999' : '#e74c3c'}">¥${Number(t.amount).toFixed(2)}</td>
            <td><span class="badge badge-${t.bill_type==='daily'?'success':'warning'}">${t.bill_type==='daily'?'日报':'月报'}</span></td>
        </tr>`;
    }).join('');

    // Pagination
    const pag = document.getElementById('pagination');
    let html = '';
    if (json.page > 1) html += `<button onclick="goPage(${json.page - 1})">上一页</button>`;
    for (let p = 1; p <= json.total_pages && p <= 10; p++) {
        html += `<button class="${p === json.page ? 'active' : ''}" onclick="goPage(${p})">${p}</button>`;
    }
    if (json.total_pages > 10) html += `<button disabled>... 共${json.total_pages}页</button>`;
    if (json.page < json.total_pages) html += `<button onclick="goPage(${json.page + 1})">下一页</button>`;
    pag.innerHTML = html;
}

function goPage(p) {
    currentPage = p;
    loadTransactions();
}
